VALUES
  ('locality-814ced5a-moex-00256', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '某甲說：「我小時候，家裡窮！爸媽總是靠打零工養家。但是，我靠著努力讀書，才當上高中老師的」。某 甲的例子可以說明下列何種現象？', '["代內水平流動", "代內向上流動", "代間水平流動", "代間向上流動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00257', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '某公立高中接獲檢舉，多位在校學生疑似受到學校教師A的性騷擾，該校依據「甲」法啟動調查程序，最 後此位教師遭到解聘及罰鍰，此懲處屬於「乙」。依據題幹資料判斷，「甲」、「乙」應分別為下列何者？', '["刑法、刑事責任", "性騷擾防治法、民事責任", "性別平等教育法、行政責任", "性別工作教育法、行政責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00258', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '某國警方原設有嚴格服儀規範，現為鼓勵各族群民眾投入警察工作，決定取消部分服儀規範，允許如頭巾 等宗教民俗信物之穿戴。該國這項作法，最符合下列何種目的？', '["保障國家安全", "維護司法正義", "推動社會安全", "維護多元文化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00259', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '2020年11月，眾所矚目的美國總統大選結果揭曉，尋求連任的川普落敗，隸屬民主黨的拜登挑戰成功， 入主白宮成為新任美國總統。關於美國總統統治正當性的敘述，下列何者正確？', '["新任總統拜登的當選受到對手的質疑，故不具正當性", "拜登是依法選出並且最終獲得選舉人團多數票支持，故具正當性", "國家領導人只要能為國家人民謀福利，即具有統治正當性", "依韋伯的分類，拜登因具群眾魅力而當選故屬魅力型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00260', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '有關目前我國政府體制運作之敘述，下列何者正確？', '["總統認為立法院通過之法案窒礙難行時得行使覆議權", "立法院可行使人事同意權對象包含審計長與檢察總長", "總統發布解散立法院之命令必須有行政院院長之副署", "總統發布行政院院長之任免命令須有行政院院長副署"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00261', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '有關目前立法委員之選舉制度，下列敘述何者正確？', '["若有志參與立委選舉須年滿30歲始具有參選資格", "區域立委係採取每區選出一席之單一選區絕對多數制", "全國不分區及僑居國外國民選出者，以全國為選舉區", "山地與平地原住民立委皆採用複數選區可讓渡投票制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00262', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '我國中央政府組織是由總統及五院共同組合而成，制度的設計兼具內閣制與總統制的特徵，在憲政體制上 較類似於混合制。關於我國憲政體制的敘述，下列何者正確？', '["行政權與立法權兩權彼此相互融合，類似英國的內閣制", "行政權與立法權兩者間的信任制度，類似美國的總統制", "國家元首為人民直選並掌部分行政權，類似法國的雙首長制", "行政院院長依例由立法院多數黨黨魁出任，類似德國的內閣制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00263', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '依照我國的地方政府體制，關於臺中市霧峰區與高雄市那瑪夏區兩者之比較，下列何者正確？', '["兩者皆為地方自治團體，設行政機關與立法機關", "兩者皆屬於市政府派出機關，不具有公法人地位", "前者為地方自治團體，後者屬於市政府派出機關", "前者屬於市政府派出機關，後者為地方自治團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00264', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '為使政黨政治健全發展，我國在解嚴後陸續通過相關法律作為人民從事政黨活動與集會遊行的法律依據。 關於政黨與利益團體之敘述，下列何者錯誤？', '["兩者之成立的法源依據皆為人民團體法", "政黨關切的議題層面一般較利益團體廣泛", "政黨以推出候選人並贏得選舉為主要目的", "利益團體以遊說與陳抗為影響政策的主要工具"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00265', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '學理上所謂防衛性民主，是指民主也應受特定價值之拘束，不得逾越憲法基礎秩序。下列何者為我國憲法 制度中採行防衛性民主思想的主要例證？', '["司法院大法官得組成憲法法庭，宣告政黨違憲並強制解散", "憲法之修改最終須經公民投票複決，以二分之一以上選舉人贊成始為通過", "立法院對行政院院長所提不信任案如未通過，1年內不得對同一行政院院長再提不信任案", "國家限制人民基本權利時，必須合乎法律保留原則之要求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
